#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;
    string s;
    scanf("%d",&t);
    while(t--){
        bool flag=true;
        cin>>s;
        stack<int> st;
        for(int i=0;i<s.size();i++){
            if(s[i]=='(')
                st.push(1);
            else if(s[i]=='[')
                st.push(2);
            else if(s[i]==')'){
                if(st.top()!=1){
                    flag=0;
                    break;
                }else
                    st.pop();
            }else{
                if(st.top()!=2){
                    flag=0;
                    break;
                }else
                    st.pop();
            }
        }
        if(st.size())
            flag=0;
        if(flag)
            printf("yes\n");
        else
            printf("no\n");
    }
    return 0;
}
